(function ($) {
  "use strict";
  function handlePreloader() {
    if ($('.loader-wrap').length) {
      $('.loader-wrap').delay(1000).fadeOut(500);
    }
  }
  if ($(".preloader-close").length) {
    $(".preloader-close").on("click", function () {
      $('.loader-wrap').delay(800).fadeOut(800);
    })
  }
  $(window).on('load', function () {
    handlePreloader();
  });
})(window.jQuery);
// /*----------------------------------------------------------------------------------------
// Category Change
// ----------------------------------------------------------------------------------------*/
$(document).on('change click blur focus keyup', '.dyna-select-dropdown', function () {
  var option = $(this).val();
  var target = $(this).attr('dyna-select-target');
  if (target) {
    var load = $('[dyna-select-load="' + target + '"]');
    $.ajax({
      url: '/select/dropdown/dyna-select/options',
      type: 'POST',
      headers: {
        'X-CSRF-TOKEN': $('meta[name="csrf-token"]').attr('content')
      },
      data: { 'option': option },
      success: function (response) {
        console.log(response);
        load.html(response);
        load.chosen().trigger("chosen:updated");
      }
    });
  }
});
cssToast.settings({
  position: 'bottomRight',
  timeout: false,
  close: true,
  pauseOnHover: true,
  transitionIn: 'fadeInUp',
  transitionOut: 'fadeOutDown',
  theme: 'light',
  onOpening: function (instance, toast) {
  },
  onClosing: function (instance, toast, closedBy) {
  }
});
function showToast(icon, title, message, duration) {
  const options = {
    title: title || '',
    titleColor: '',
    titleSize: '',
    titleLineHeight: '',
    message: message || '',
    messageColor: '',
    messageSize: '',
    messageLineHeight: '',
    backgroundColor: '',
    theme: 'light',
    color: '',
    icon: '',
    iconText: '',
    iconColor: '',
    iconUrl: null,
    timeout: duration || 5000
  };
  switch (icon) {
    case 'success':
      options.titleColor = '#ffffff',
        options.messageColor = '#ffffff',
        options.icon = 'fa fa-check-circle';
      options.backgroundColor = '#00ee36';
      options.iconColor = '#ffffff';
      break;
    case 'error':
      options.titleColor = '#ffffff',
        options.messageColor = '#ffffff',
        options.icon = 'fa fa-times-circle';
      options.backgroundColor = '#ff0018';
      options.iconColor = '#ffffff';
      break;
    case 'warning':
      options.icon = 'fa fa-exclamation-triangle';
      options.backgroundColor = '#ffd000';
      options.iconColor = '#212529';
      break;
    case 'info':
      options.icon = 'fa fa-info-circle';
      options.backgroundColor = '#00d5ff';
      options.iconColor = '#ffffff';
      break;
    case 'question':
      options.titleColor = '#ffffff',
        options.messageColor = '#ffffff',
        options.icon = 'fa fa-circle-question';
      options.backgroundColor = '#0087ff';
      options.iconColor = '#ffffff';
      break;
    case 'light':
      options.icon = 'fa fa-message-lines';
      options.backgroundColor = '#dedede';
      options.iconColor = '#333333';
      break;
    case 'dark':
      options.titleColor = '#ffffff',
        options.messageColor = '#ffffff',
        options.icon = 'fa fa-message-lines';
      options.backgroundColor = '#002343';
      options.iconColor = '#ffffff';
      break;
    default:
      options.icon = 'fa fa-bell';
      options.backgroundColor = '#6c757d';
      options.iconColor = '#ffffff';
      break;
  }
  cssToast.show(options);
}
function successToast(title, message, duration) {
  showToast('success', title, message, duration);
}
function errorToast(title, message, duration) {
  showToast('error', title, message, duration);
}
function warningToast(title, message, duration) {
  showToast('warning', title, message, duration);
}
function infoToast(title, message, duration) {
  showToast('info', title, message, duration);
}
function questionToast(title, message, duration) {
  showToast('question', title, message, duration);
}
function lightToast(title, message, duration) {
  showToast('light', title, message, duration);
}
function darkToast(title, message, duration) {
  showToast('dark', title, message, duration);
}
function showAlert(icon, title, message, reload = false, buttonText = 'OK') {
  const alertOptions = {
    icon: icon,
    title: title,
    html: message,
    showConfirmButton: true,
    confirmButtonText: buttonText,
  };
  Swal.fire(alertOptions).then((result) => {
    if (result.isConfirmed && reload) {
      window.location.reload();
    }
  });
}
function successAlert(title, message, reload = false, buttonText = 'OK') {
  showAlert('success', title, message, reload, buttonText);
}
function errorAlert(title, message, reload = false, buttonText = 'OK') {
  showAlert('error', title, message, reload, buttonText);
}
function warningAlert(title, message, reload = false, buttonText = 'OK') {
  showAlert('warning', title, message, reload, buttonText);
}
function infoAlert(title, message, reload = false, buttonText = 'OK') {
  showAlert('info', title, message, reload, buttonText);
}
function questionAlert(title, message, reload = false, buttonText = 'OK') {
  showAlert('question', title, message, reload, buttonText);
}
function lightAlert(title, message, reload = false, buttonText = 'OK') {
  showAlert(null, title, message, reload, buttonText);
}
function notifyToast($title, $message, $time) {
  toastr.options = {
    "closeButton": true,
    "debug": false,
    "newestOnTop": true,
    "progressBar": false,
    "positionClass": "toast-bottom-right",
    "preventDuplicates": true,
    "showDuration": "300",
    "hideDuration": "1000",
    "timeOut": $time,
    "extendedTimeOut": 0,
    "showEasing": "swing",
    "hideEasing": "linear",
    "showMethod": "fadeIn",
    "hideMethod": "fadeOut",
    "tapToDismiss": false,
    "toastClass": "toast toast-info"
  };
  toastr.success($message, $title);
}
const baseUrl = window.location.origin;
const audioSources = {
  'success': `${baseUrl}/treasury/sounds/success.mp3`,
  'error': `${baseUrl}/treasury/sounds/error.mp3`,
  'info': `${baseUrl}/treasury/sounds/info.mp3`,
  'warning': `${baseUrl}/treasury/sounds/warning.mp3`,
  'reminder': `${baseUrl}/treasury/sounds/reminder.mp3`,
  'notify': `${baseUrl}/treasury/sounds/notify.mp3`
};
let userInteracted = false;
function playAudio(type) {
  if (!userInteracted) return;
  const audioPath = audioSources[type] || audioSources['notify'];
  const audio = new Audio(audioPath);
  audio.oncanplaythrough = () => {
    const playedPromise = audio.play();
    if (playedPromise) {
      playedPromise.catch((e) => {
        if (e.name !== 'NotAllowedError' && e.name !== 'NotSupportedError') {
          //console.log(e);
        }
      }).then(() => {
      });
    }
  };
}
function detectUserInteraction() {
  function interactionHandler() {
    userInteracted = true;
    document.removeEventListener('click', interactionHandler);
    document.removeEventListener('mousemove', interactionHandler);
    document.removeEventListener('keypress', interactionHandler);
    document.removeEventListener('touchstart', interactionHandler);
  }
  document.addEventListener('click', interactionHandler);
  document.addEventListener('mousemove', interactionHandler);
  document.addEventListener('keypress', interactionHandler);
  document.addEventListener('touchstart', interactionHandler);
}
detectUserInteraction();
$(document).ready(function () {
  function copyToClipboard() {
    if (window.clipboardInstance) {
      window.clipboardInstance.destroy();
    }
    window.clipboardInstance = new ClipboardJS(".copy-btn");
    window.clipboardInstance.on("success", function (event) {
      darkToast("Copied:", event.text, 5000);
      event.clearSelection();
    });
    window.clipboardInstance.on("error", function () {
      errorToast("Error!", "Failed to copy! Please try again.", 5000);
    });
  }
  copyToClipboard();
  window.copyToClipboard = copyToClipboard;
});

